import React, { useEffect, useState } from 'react'
import { Img_URL, fetchMovieList } from '../../utils/fetchApi';
import { Link } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';

const Upcoming = () => {
    const [page,setPage]=useState(1);
    const [UpcomingMovieList,setUpcomingMovieList]=useState([])

    const loadMoreHandle=()=>{
     setPage((prev)=> prev + 1);
     refetch();
     if(UpcomingList.length!==0){
         setUpcomingMovieList((prev)=> [...prev,...UpcomingList]);
         console.log(UpcomingList);
     }else{
        return console.log('!!!');
     }
   }

    const { isLoading,isError,error ,data: UpcomingList,refetch} = useQuery({
        queryKey: ["UpcomingList"],
        queryFn: () =>
          fetchMovieList("upcoming",`${page}`).then((res) => {
              if(page===1){
                  setUpcomingMovieList(res.results);
              }
              console.log(res.results);
            return res.results;
          }),
      });



      useEffect(()=>{
        refetch();
      },[refetch,page,isLoading]);

      if (isLoading) {
        return (
          <div className="loading">
            <h1>Loading...</h1>
          </div>
        );
      } else if (isError) {
        return (
          <div className="error">
            <p>{error.message}</p>
          </div>
        );
      } else
  return (
    <div className="Popular">
          <h1>Upcoming Movies</h1>
          <div>
          {UpcomingMovieList?.map((item,index) => (
                item.poster_path!==null &&
                <Link to={`/movie/${item.id}`} className="card" key={index}>
                <img src={`${Img_URL}${item.poster_path}`} alt="img" />
              </Link>    
          ))}
          </div>
         <button onClick={loadMoreHandle}>More</button>
        </div>
  )
  }
export default Upcoming
